from typing import Optional

def greet(name: str, excited: bool = False) -> str:
    if excited:
        return f'HELLO, {name.upper()}!!!'
    return f'Hello, {name}.'

def find_user(user_id: int) -> Optional[str]:
    users = {1: 'Alice', 2: 'Bob'}
    return users.get(user_id)

print(greet('Alice', excited=True))
print(greet('Bob'))
print(find_user(1))
print(find_user(99))

